    17→package topologycache
    18→
    19→import (
    20→	"fmt"
    21→	"math"
    22→
    23→	v1 "k8s.io/api/core/v1"
    24→	discovery "k8s.io/api/discovery/v1"
    25→	"k8s.io/klog/v2"
    26→)
    27→
    28→// RemoveHintsFromSlices removes topology hints on EndpointSlices and returns
    29→// updated lists of EndpointSlices to create and update.
    30→func RemoveHintsFromSlices(si *SliceInfo) ([]*discovery.EndpointSlice, []*discovery.EndpointSlice) {
    31→	// Remove hints on all EndpointSlices we were already going to change.
    32→	slices := append(si.ToCreate, si.ToUpdate...)
    33→	for _, slice := range slices {
    34→		for i := range slice.Endpoints {
    35→			slice.Endpoints[i].Hints = nil
    36→		}
    37→	}
    38→
    39→	// Remove hints on all unchanged EndpointSlices and mark them for update
    40→	// if any already had hints. We use j to track the number/index of slices
    41→	// that are still unchanged.
    42→	j := 0
    43→	for _, slice := range si.Unchanged {
    44→		changed := false
    45→		for i, endpoint := range slice.Endpoints {
    46→			if endpoint.Hints != nil {
    47→				// Unchanged slices are still direct copies from informer cache.
    48→				// Need to deep copy before we make any modifications to avoid
    49→				// accidentally changing informer cache.
    50→				slice = slice.DeepCopy()
    51→				slice.Endpoints[i].Hints = nil
    52→				changed = true
    53→			}
    54→		}
    55→		if changed {
    56→			si.ToUpdate = append(si.ToUpdate, slice)
    57→		} else {
    58→			si.Unchanged[j] = slice
    59→			j++
    60→		}
    61→	}
    62→
    63→	// truncate si.Unchanged so it only includes slices that are still
    64→	// unchanged.
    65→	si.Unchanged = si.Unchanged[:j]
    66→
    67→	return si.ToCreate, si.ToUpdate
    68→}
    69→
    70→// FormatWithAddressType foramts a given string by adding an addressType to the end of it.
    71→func FormatWithAddressType(s string, addressType discovery.AddressType) string {
    72→	return fmt.Sprintf("%s, addressType: %s", s, addressType)
    73→}
    74→
    75→// redistributeHints redistributes hints based in the provided EndpointSlices.
    76→// It allocates endpoints from the provided givingZones to the provided
    77→// receivingZones. This returns a map that represents the changes in allocated
    78→// endpoints by zone.
    79→func redistributeHints(logger klog.Logger, slices []*discovery.EndpointSlice, givingZones, receivingZones map[string]int) map[string]int {
    80→	redistributions := map[string]int{}
    81→
    82→	for _, slice := range slices {
    83→		for i, endpoint := range slice.Endpoints {
    84→			if !EndpointReady(endpoint) {
    85→				endpoint.Hints = nil
    86→				continue
    87→			}
    88→			if len(givingZones) == 0 || len(receivingZones) == 0 {
    89→				return redistributions
    90→			}
    91→			if endpoint.Zone == nil || *endpoint.Zone == "" {
    92→				// This should always be caught earlier in AddHints()
    93→				logger.Info("Endpoint found without zone specified")
    94→				continue
    95→			}
    96→
    97→			givingZone := *endpoint.Zone
    98→			numToGive, ok := givingZones[givingZone]
    99→			if ok && numToGive > 0 {
   100→				for receivingZone, numToReceive := range receivingZones {
   101→					if numToReceive > 0 {
   102→						slice.Endpoints[i].Hints = &discovery.EndpointHints{ForZones: []discovery.ForZone{{Name: receivingZone}}}
   103→						if numToGive == 1 {
   104→							delete(givingZones, givingZone)
   105→						} else {
   106→							givingZones[givingZone]--
   107→						}
   108→						if numToReceive == 1 {
   109→							delete(receivingZones, receivingZone)
   110→						} else {
   111→							receivingZones[receivingZone]--
   112→						}
   113→
   114→						redistributions[receivingZone]++
   115→						redistributions[givingZone]--
   116→
   117→						break
   118→					}
   119→				}
   120→			}
   121→		}
   122→	}
   123→	return redistributions
   124→}
   125→
   126→// getGivingAndReceivingZones returns the number of endpoints each zone should
   127→// give to other zones along with the number of endpoints each zone should
   128→// receive from other zones. This is calculated with the provided allocations
   129→// (desired state) and allocatedHintsByZone (current state).
