   104→							delete(givingZones, givingZone)
   105→						} else {
   106→							givingZones[givingZone]--
   107→						}
   108→						if numToReceive == 1 {
   109→							delete(receivingZones, receivingZone)
   110→						} else {
   111→							receivingZones[receivingZone]--
   112→						}
   113→
   114→						redistributions[receivingZone]++
   115→						redistributions[givingZone]--
   116→
   117→						break
   118→					}
   119→				}
   120→			}
   121→		}
   122→	}
   123→	return redistributions
   124→}
   125→
   126→// getGivingAndReceivingZones returns the number of endpoints each zone should
   127→// give to other zones along with the number of endpoints each zone should
   128→// receive from other zones. This is calculated with the provided allocations
   129→// (desired state) and allocatedHintsByZone (current state).
   130→func getGivingAndReceivingZones(allocations map[string]allocation, allocatedHintsByZone map[string]int) (map[string]int, map[string]int) {
   131→	// 1. Determine the precise number of additional endpoints each zone has
   132→	//    (giving) or needs (receiving).
   133→	givingZonesDesired := map[string]float64{}
   134→	receivingZonesDesired := map[string]float64{}
   135→
   136→	for zone, allocation := range allocations {
   137→		allocatedHints, _ := allocatedHintsByZone[zone]
   138→		target := allocation.desired
   139→		if float64(allocatedHints) > target {
   140→			givingZonesDesired[zone] = float64(allocatedHints) - target
   141→		} else if float64(allocatedHints) < target {
   142→			receivingZonesDesired[zone] = target - float64(allocatedHints)
   143→		}
   144→	}
   145→
   146→	// 2. Convert the precise numbers needed into ints representing real
   147→	//    endpoints given from one zone to another.
   148→	givingZones := map[string]int{}
   149→	receivingZones := map[string]int{}
