   151→	for {
   152→		givingZone, numToGive := getMost(givingZonesDesired)
   153→		receivingZone, numToReceive := getMost(receivingZonesDesired)
   154→
   155→		// return early if any of the following are true:
   156→		// - giving OR receiving zone are unspecified
   157→		// - giving AND receiving zones have less than 1 endpoint left to give or receive
   158→		// - giving OR receiving zones have less than 0.5 endpoints left to give or receive
   159→		if givingZone == "" || receivingZone == "" || (numToGive < 1.0 && numToReceive < 1.0) || numToGive < 0.5 || numToReceive < 0.5 {
