   161→		}
   162→
   163→		givingZones[givingZone]++
   164→		givingZonesDesired[givingZone]--
   165→		receivingZones[receivingZone]++
   166→		receivingZonesDesired[receivingZone]--
   167→	}
   168→
   169→	return givingZones, receivingZones
   170→}
