   172→// getMost accepts a map[string]float64 and returns the string and float64 that
   173→// represent the greatest value in this provided map. This function is not very
   174→// efficient but it is expected that len() will rarely be greater than 2.
   175→func getMost(zones map[string]float64) (string, float64) {
   176→	zone := ""
   177→	num := 0.0
   178→	for z, n := range zones {
   179→		if n > num {
   180→			zone = z
   181→			num = n
   182→		}
   183→	}
   184→
   185→	return zone, num
   186→}
   187→
   188→// getHintsByZone returns the number of hints allocated to each zone by the
   189→// provided EndpointSlice. This function returns nil to indicate that the
   190→// current allocations are invalid and that the EndpointSlice needs to be
   191→// updated. This could be caused by:
   192→// - A hint for a zone that no longer requires any allocations.
   193→// - An endpoint with no hints.
   194→// - Hints that would make minimum allocations impossible.
   195→func getHintsByZone(slice *discovery.EndpointSlice, allocatedHintsByZone EndpointZoneInfo, allocations map[string]allocation) map[string]int {
   196→	hintsByZone := map[string]int{}
   197→	for _, endpoint := range slice.Endpoints {
   198→		if !EndpointReady(endpoint) {
   199→			continue
   200→		}
   201→		if endpoint.Hints == nil || len(endpoint.Hints.ForZones) == 0 {
   202→			return nil
   203→		}
   204→
   205→		for i := range endpoint.Hints.ForZones {
   206→			zone := endpoint.Hints.ForZones[i].Name
   207→			if _, ok := allocations[zone]; !ok {
   208→				return nil
   209→			}
   210→			hintsByZone[zone]++
   211→		}
   212→	}
   213→
   214→	for zone, numHints := range hintsByZone {
   215→		alreadyAllocated, _ := allocatedHintsByZone[zone]
   216→		allocation, ok := allocations[zone]
   217→		if !ok || (numHints+alreadyAllocated) > allocation.maximum {
   218→			return nil
   219→		}
   220→	}
   221→
   222→	return hintsByZone
   223→}
