   225→// serviceOverloaded returns true if the Service has an insufficient amount of
   226→// endpoints for any zone.
   227→func serviceOverloaded(ezi EndpointZoneInfo, zoneRatios map[string]float64) bool {
   228→	if len(ezi) == 0 {
   229→		return false
   230→	}
   231→	if len(zoneRatios) == 0 {
   232→		return true
   233→	}
   234→
   235→	totalEndpoints := 0.0
   236→	for _, numEndpoints := range ezi {
   237→		totalEndpoints += float64(numEndpoints)
   238→	}
   239→
   240→	for zone, ratio := range zoneRatios {
   241→		svcEndpoints, ok := ezi[zone]
   242→		if !ok {
   243→			return true
   244→		}
   245→		minEndpoints := math.Ceil(totalEndpoints * ratio * (1 / (1 + overloadThreshold)))
   246→		if svcEndpoints < int(minEndpoints) {
   247→			return true
   248→		}
   249→	}
   250→
   251→	return false
   252→}
